<h1>Gestion des offres</h1>
<form method="post" class="card"><input type="hidden" name="_csrf" value="<?= htmlspecialchars($csrfToken) ?>"><label>Jeu</label><select name="game_id"><?php foreach($games as $g): ?><option value="<?= (int)$g['id'] ?>"><?= htmlspecialchars($g['name']) ?></option><?php endforeach; ?></select><label>Nom</label><input name="name" required><label>Prix mensuel</label><input name="price_monthly" type="number" step="0.01" required><label>RAM MB</label><input name="ram_mb" type="number" required><label>CPU Cores</label><input name="cpu_cores" type="number" required><label>Stockage GB</label><input name="storage_gb" type="number" required><label>Slots</label><input name="slots" type="number"><label>Description</label><textarea name="description"></textarea><label><input type="checkbox" name="is_active" checked> Actif</label><button class="btn" type="submit">Créer offre</button></form>
<table class="table"><tr><th>Offre</th><th>Jeu</th><th>Prix</th><th>Ressources</th><th>Statut</th></tr><?php foreach($offers as $o): ?><tr><td><?= htmlspecialchars($o['name']) ?></td><td><?= htmlspecialchars($o['game_name']) ?></td><td><?= number_format((float)$o['price_monthly'],2) ?>€</td><td><?= (int)$o['ram_mb'] ?> MB / <?= (int)$o['cpu_cores'] ?> CPU / <?= (int)$o['storage_gb'] ?> GB</td><td><?= (int)$o['is_active'] ? 'Actif':'Inactif' ?></td></tr><?php endforeach; ?></table>
